window.BILARA = window.BILARA || {};
window.BILARA["dn19"] = window.BILARA["dn19"] || {};
window.BILARA["dn19"]["vi"] = {
  "dn19:0.1": "Trường Bộ Kinh 19 ",
  "dn19:0.2": "Kinh Đại Điển Tôn ",
  "dn19:1.1": "Như vầy tôi nghe—",
  "dn19:1.2": "Một thời Thế Tôn trú tại Rājagaha, trên núi Gijjhakūṭa. ",
  "dn19:1.3": "Rồi vào lúc đêm đã khuya, Pañcasikha con của càn-thát-bà với dung sắc tuyệt đẹp chiếu sáng khắp núi Gijjhakūṭa, đi đến chỗ Thế Tôn; sau khi đến, đảnh lễ Thế Tôn rồi đứng một bên. Đứng một bên, Pañcasikha con của càn-thát-bà bạch Thế Tôn rằng: ",
  "dn19:1.4": "“Bạch Thế Tôn, điều gì con đã nghe trực tiếp, tiếp nhận trực tiếp từ chư thiên cõi Ba Mươi Ba, con xin trình lên Thế Tôn.” ",
  "dn19:1.5": "“Hãy trình cho Ta nghe, này Pañcasikha”, Thế Tôn đáp. ",
  "dn19:2.0": "1. Hội chúng chư thiên ",
  "dn19:2.1": "“Bạch Thế Tôn, vào những ngày trước đây, vào ngày Bố-tát rằm, tháng tự tứ, đêm trăng tròn đầy đủ, toàn thể chư thiên cõi Ba Mươi Ba tụ họp, ngồi tại Thiện Pháp Đường; ",
  "dn19:2.2": "đại chúng chư thiên ngồi xung quanh, và bốn vị Đại Thiên Vương ngồi ở bốn hướng; ",
  "dn19:2.3": "ở hướng đông, Đại Thiên Vương Dhataraṭṭha ngồi xoay mặt về hướng tây, hướng về chư thiên; ",
  "dn19:2.4": "ở hướng nam, Đại Thiên Vương Virūḷhaka ngồi xoay mặt về hướng bắc, hướng về chư thiên; ",
  "dn19:2.5": "ở hướng tây, Đại Thiên Vương Virūpakkha ngồi xoay mặt về hướng đông, hướng về chư thiên; ",
  "dn19:2.6": "ở hướng bắc, Đại Thiên Vương Vessavaṇa ngồi xoay mặt về hướng nam, hướng về chư thiên. ",
  "dn19:2.7": "Bạch Thế Tôn, khi toàn thể chư thiên cõi Ba Mươi Ba tụ họp, ngồi tại Thiện Pháp Đường, đại chúng chư thiên ngồi xung quanh, và bốn vị Đại Thiên Vương ngồi ở bốn hướng, đó là các chỗ ngồi của các vị ấy; ",
  "dn19:2.8": "phía sau là chỗ ngồi của chúng con. ",
  "dn19:3.1": "Bạch Thế Tôn, các vị chư thiên đã sống đời phạm hạnh dưới Thế Tôn và mới được sinh vào cõi Ba Mươi Ba, các vị ấy tỏa sáng hơn các chư thiên khác về dung sắc và danh tiếng. ",
  "dn19:3.2": "Vì vậy, bạch Thế Tôn, chư thiên cõi Ba Mươi Ba hoan hỷ, vui mừng, sinh tâm hỷ lạc: ",
  "dn19:3.3": "‘Ôi quý vị, các cõi trời đầy lên, các cõi a-tu-la giảm đi.’ ",
  "dn19:3.4": "Rồi, bạch Thế Tôn, vua trời Đế Thích sau khi biết sự vui mừng của chư thiên cõi Ba Mươi Ba, tán thán bằng các bài kệ này: ",
  "dn19:3.5": "‘Ôi chư thiên đang vui mừng, ",
  "dn19:3.6": "Chư thiên Ba Mươi Ba cùng Đế Thích; ",
  "dn19:3.7": "Đảnh lễ đức Như Lai, ",
  "dn19:3.8": "Và sự hoàn hảo của Pháp. ",
  "dn19:3.9": "Thấy chư thiên mới, ",
  "dn19:3.10": "Có dung sắc, có danh tiếng; ",
  "dn19:3.11": "Đã sống phạm hạnh dưới Thiện Thệ, ",
  "dn19:3.12": "Và đến đây sinh. ",
  "dn19:3.13": "Các vị ấy vượt trội các chư thiên khác, ",
  "dn19:3.14": "Về dung sắc, danh tiếng, thọ mạng; ",
  "dn19:3.15": "Là đệ tử của bậc đại trí tuệ, ",
  "dn19:3.16": "Đã đạt được sự thù thắng ở đây. ",
  "dn19:3.17": "Thấy vậy, chư thiên hoan hỷ, ",
  "dn19:3.18": "Chư thiên Ba Mươi Ba cùng Đế Thích; ",
  "dn19:3.19": "Đảnh lễ đức Như Lai, ",
  "dn19:3.20": "Và sự hoàn hảo của Pháp.’ ",
  "dn19:3.21": "Vì vậy, bạch Thế Tôn, chư thiên cõi Ba Mươi Ba càng hoan hỷ, vui mừng, sinh tâm hỷ lạc hơn: ",
  "dn19:3.22": "‘Ôi quý vị, các cõi trời đầy lên, các cõi a-tu-la giảm đi.’ ",
  "dn19:4.0": "2. Tám đức tính đúng sự thật ",
  "dn19:4.1": "Rồi, bạch Thế Tôn, vua trời Đế Thích sau khi biết sự vui mừng của chư thiên cõi Ba Mươi Ba, nói với chư thiên cõi Ba Mươi Ba: ",
  "dn19:4.2": "‘Thưa quý vị, quý vị có muốn nghe tám đức tính đúng sự thật của Thế Tôn không?’ ",
  "dn19:4.3": "‘Thưa tôn giả, chúng tôi muốn nghe tám đức tính đúng sự thật của Thế Tôn.’ ",
  "dn19:4.4": "Rồi, bạch Thế Tôn, vua trời Đế Thích trình bày cho chư thiên cõi Ba Mươi Ba nghe tám đức tính đúng sự thật của Thế Tôn: ",
  "dn19:5.1": "‘Chư vị thiên cõi Ba Mươi Ba nghĩ thế nào? ",
  "dn19:5.2": "Thế Tôn ấy đã thực hành vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương xót thế gian, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người. ",
  "dn19:5.3": "Một bậc Đạo sư đã thực hành vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương xót thế gian, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:6.1": "Pháp được Thế Tôn ấy khéo thuyết giảng, thiết thực hiện tại, không có thời gian, đến để mà thấy, có khả năng hướng thượng, được các bậc trí tự mình chứng ngộ. ",
  "dn19:6.2": "Một bậc Đạo sư thuyết giảng Pháp có khả năng hướng thượng như vậy, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:7.1": "‘Đây là thiện’ được Thế Tôn ấy khéo chế định, ‘đây là bất thiện’ được khéo chế định. ",
  "dn19:7.2": "‘Đây là có tội, đây là không có tội, đây là nên thực hành, đây là không nên thực hành, đây là thấp hèn, đây là cao thượng, đây là phần đen phần trắng đối đãi’ được khéo chế định. ",
  "dn19:7.3": "Một bậc Đạo sư khéo chế định các pháp thiện, bất thiện, có tội, không có tội, nên thực hành, không nên thực hành, thấp hèn, cao thượng, phần đen phần trắng đối đãi như vậy, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:8.1": "Con đường đưa đến Niết-bàn cho các đệ tử được Thế Tôn ấy khéo chế định, Niết-bàn và con đường hòa quyện với nhau. ",
  "dn19:8.2": "Ví như nước sông Hằng hòa quyện, gặp nhau với nước sông Yamunā; ",
  "dn19:8.3": "cũng vậy, con đường đưa đến Niết-bàn cho các đệ tử được Thế Tôn ấy khéo chế định, Niết-bàn và con đường hòa quyện với nhau. ",
  "dn19:8.4": "Một bậc Đạo sư khéo chế định con đường đưa đến Niết-bàn như vậy, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:9.1": "Thế Tôn ấy có được lợi lộc, có được danh tiếng, các vị Sát-đế-lỵ như thể yêu mến Ngài, nhưng Thế Tôn ấy dùng thức ăn mà không còn kiêu ngạo. ",
  "dn19:9.2": "Một bậc Đạo sư dùng thức ăn mà không còn kiêu ngạo như vậy, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:10.1": "Thế Tôn ấy có bạn là các bậc hữu học đang thực hành và các bậc A-la-hán đã viên thành phạm hạnh. ",
  "dn19:10.2": "Thế Tôn gạt họ ra một bên để sống chuyên chú vào niềm vui của sự tĩnh lặng. ",
  "dn19:10.3": "Một bậc Đạo sư chuyên chú vào niềm vui của sự tĩnh lặng như vậy, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:11.1": "Thế Tôn ấy nói sao làm vậy, làm sao nói vậy, như vậy là nói sao làm vậy, làm sao nói vậy. ",
  "dn19:11.2": "Một bậc Đạo sư thực hành pháp theo pháp như vậy, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:12.1": "Thế Tôn ấy đã vượt qua hoài nghi, đoạn tận do dự, ý chí đã viên thành, chủ ý đã hướng về đời sống phạm hạnh căn bản. ",
  "dn19:12.2": "Một bậc Đạo sư đã vượt qua hoài nghi, đoạn tận do dự, ý chí đã viên thành, chủ ý đã hướng về đời sống phạm hạnh căn bản như vậy, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy.’ ",
  "dn19:12.3": "Bạch Thế Tôn, đây là tám đức tính đúng sự thật của Thế Tôn mà vua trời Đế Thích đã trình bày cho chư thiên cõi Ba Mươi Ba. ",
  "dn19:12.4": "Vì vậy, bạch Thế Tôn, chư thiên cõi Ba Mươi Ba càng hoan hỷ, vui mừng, sinh tâm hỷ lạc hơn sau khi nghe tám đức tính đúng sự thật của Thế Tôn. ",
  "dn19:13.1": "Bạch Thế Tôn, khi ấy có một số chư thiên nói rằng: ",
  "dn19:13.2": "‘Ôi quý vị, giá mà có bốn vị Chánh Đẳng Giác xuất hiện ở đời và thuyết giảng Pháp như Thế Tôn. ",
  "dn19:13.3": "Điều ấy sẽ vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương xót thế gian, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người.’ ",
  "dn19:13.4": "Một số chư thiên nói: ",
  "dn19:13.5": "‘Thôi, quý vị, không cần bốn vị Chánh Đẳng Giác, ôi quý vị, giá mà có ba vị Chánh Đẳng Giác xuất hiện ở đời và thuyết giảng Pháp như Thế Tôn. ",
  "dn19:13.6": "Điều ấy sẽ vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương xót thế gian, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người.’ ",
  "dn19:13.7": "Một số chư thiên nói: ",
  "dn19:13.8": "‘Thôi, quý vị, không cần ba vị Chánh Đẳng Giác, ôi quý vị, giá mà có hai vị Chánh Đẳng Giác xuất hiện ở đời và thuyết giảng Pháp như Thế Tôn. ",
  "dn19:13.9": "Điều ấy sẽ vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương xót thế gian, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người.’ ",
  "dn19:14.1": "Khi được nói vậy, bạch Thế Tôn, vua trời Đế Thích nói với chư thiên cõi Ba Mươi Ba: ",
  "dn19:14.2": "‘Thưa quý vị, điều ấy không thể có, không có trường hợp hai vị A-la-hán, Chánh Đẳng Giác đồng thời xuất hiện trong một thế giới, không thể có trường hợp ấy. ",
  "dn19:14.3": "Ôi quý vị, giá mà Thế Tôn ấy ít bệnh, ít đau, sống lâu dài. ",
  "dn19:14.4": "Điều ấy sẽ vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương xót thế gian, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người.’ ",
  "dn19:14.5": "Rồi, bạch Thế Tôn, chư thiên cõi Ba Mươi Ba tụ họp tại Thiện Pháp Đường vì mục đích nào, sau khi suy xét và thảo luận về mục đích ấy, bốn vị Đại Thiên Vương cũng phát biểu về mục đích ấy. ",
  "dn19:14.6": "Sau khi được bốn vị Đại Thiên Vương chỉ dạy về mục đích ấy, các ngài đứng yên tại chỗ ngồi của mình không rời đi. ",
  "dn19:14.7": "Các vị vua ấy sau khi được dạy bảo, ",
  "dn19:14.8": "Tiếp nhận lời chỉ dạy; ",
  "dn19:14.9": "Tâm vắng lặng, an tịnh, ",
  "dn19:14.10": "Đứng tại chỗ ngồi của mình. ",
  "dn19:15.1": "Rồi, bạch Thế Tôn, từ hướng bắc xuất hiện một luồng ánh sáng lớn, hào quang hiện ra, vượt qua cả uy lực của chư thiên. ",
  "dn19:15.2": "Rồi, bạch Thế Tôn, vua trời Đế Thích nói với chư thiên cõi Ba Mươi Ba: ",
  "dn19:15.3": "‘Thưa quý vị, khi các dấu hiệu hiện ra, ánh sáng lớn xuất hiện, hào quang hiện ra, thì Phạm thiên sẽ xuất hiện; ",
  "dn19:15.4": "đó là điềm báo trước của sự xuất hiện của Phạm thiên, tức là ánh sáng xuất hiện, hào quang hiện ra. ",
  "dn19:15.5": "Khi các dấu hiệu hiện ra, ",
  "dn19:15.6": "Phạm thiên sẽ xuất hiện; ",
  "dn19:15.7": "Đó là điềm báo của Phạm thiên, ",
  "dn19:15.8": "Hào quang rộng lớn và vĩ đại.’ ",
  "dn19:16.0": "3. Lời nói của Phạm thiên Sanaṅkumāra ",
  "dn19:16.1": "Rồi, bạch Thế Tôn, chư thiên cõi Ba Mươi Ba ngồi yên mỗi vị trên chỗ ngồi của mình: ",
  "dn19:16.2": "‘Chúng ta sẽ biết hào quang này, kết quả của nó sẽ là gì, chỉ sau khi chứng kiến, chúng ta mới đi.’ ",
  "dn19:16.3": "Bốn vị Đại Thiên Vương cũng ngồi yên mỗi vị trên chỗ ngồi của mình: ",
  "dn19:16.4": "‘Chúng ta sẽ biết hào quang này, kết quả của nó sẽ là gì, chỉ sau khi chứng kiến, chúng ta mới đi.’ ",
  "dn19:16.5": "Nghe vậy, chư thiên cõi Ba Mươi Ba đồng lòng đồng ý: ",
  "dn19:16.6": "‘Chúng ta sẽ biết hào quang này, kết quả của nó sẽ là gì, chỉ sau khi chứng kiến, chúng ta mới đi.’ ",
  "dn19:16.7": "Bạch Thế Tôn, khi Phạm thiên Sanaṅkumāra xuất hiện giữa chư thiên cõi Ba Mươi Ba, ngài hiện ra sau khi tạo ra một tự thân thô hơn. ",
  "dn19:16.8": "Bạch Thế Tôn, dung sắc tự nhiên của Phạm thiên không nằm trong tầm mắt của chư thiên cõi Ba Mươi Ba. ",
  "dn19:16.9": "Bạch Thế Tôn, khi Phạm thiên Sanaṅkumāra xuất hiện giữa chư thiên cõi Ba Mươi Ba, ngài tỏa sáng hơn các chư thiên khác về dung sắc và danh tiếng. ",
  "dn19:16.10": "Ví như, bạch Thế Tôn, một hình tượng bằng vàng tỏa sáng hơn một hình tượng người; ",
  "dn19:16.11": "cũng vậy, bạch Thế Tôn, khi Phạm thiên Sanaṅkumāra xuất hiện giữa chư thiên cõi Ba Mươi Ba, ngài tỏa sáng hơn các chư thiên khác về dung sắc và danh tiếng. ",
  "dn19:16.12": "Bạch Thế Tôn, khi Phạm thiên Sanaṅkumāra xuất hiện giữa chư thiên cõi Ba Mươi Ba, không một vị thiên nào trong hội chúng ấy đảnh lễ, đứng dậy hay mời ngồi. ",
  "dn19:16.13": "Tất cả đều im lặng, chắp tay, ngồi kiết già: ",
  "dn19:16.14": "‘Chỗ ngồi của vị thiên nào mà Phạm thiên Sanaṅkumāra muốn, thì ngài sẽ ngồi trên chỗ ngồi của vị thiên ấy.’ ",
  "dn19:16.15": "Bạch Thế Tôn, chỗ ngồi của vị thiên nào mà Phạm thiên Sanaṅkumāra ngồi lên, thì vị thiên ấy nhận được nỗi hân hoan cao quý, nhận được niềm hỷ lạc cao quý. ",
  "dn19:17.1": "Ví như, bạch Thế Tôn, một vị vua Sát-đế-lỵ đã làm lễ quán đảnh, mới được tấn phong vương vị, nhận được nỗi hân hoan cao quý, nhận được niềm hỷ lạc cao quý; ",
  "dn19:17.2": "cũng vậy, bạch Thế Tôn, chỗ ngồi của vị thiên nào mà Phạm thiên Sanaṅkumāra ngồi lên, thì vị thiên ấy nhận được nỗi hân hoan cao quý, nhận được niềm hỷ lạc cao quý. ",
  "dn19:17.3": "Rồi, bạch Thế Tôn, Phạm thiên Sanaṅkumāra sau khi biết sự vui mừng của chư thiên cõi Ba Mươi Ba, ẩn mình tán thán bằng các bài kệ này: ",
  "dn19:17.4": "‘Ôi chư thiên đang vui mừng, ",
  "dn19:17.5": "Chư thiên Ba Mươi Ba cùng Đế Thích; ",
  "dn19:17.6": "Đảnh lễ đức Như Lai, ",
  "dn19:17.7": "Và sự hoàn hảo của Pháp. ",
  "dn19:17.8": "Thấy chư thiên mới, ",
  "dn19:17.9": "Có dung sắc, có danh tiếng; ",
  "dn19:17.10": "Đã sống phạm hạnh dưới Thiện Thệ, ",
  "dn19:17.11": "Và đến đây sinh. ",
  "dn19:17.12": "Các vị ấy vượt trội các chư thiên khác, ",
  "dn19:17.13": "Về dung sắc, danh tiếng, thọ mạng; ",
  "dn19:17.14": "Là đệ tử của bậc đại trí tuệ, ",
  "dn19:17.15": "Đã đạt được sự thù thắng ở đây. ",
  "dn19:17.16": "Thấy vậy, chư thiên hoan hỷ, ",
  "dn19:17.17": "Chư thiên Ba Mươi Ba cùng Đế Thích; ",
  "dn19:17.18": "Đảnh lễ đức Như Lai, ",
  "dn19:17.19": "Và sự hoàn hảo của Pháp.’ ",
  "dn19:18.1": "Bạch Thế Tôn, Phạm thiên Sanaṅkumāra đã nói về ý nghĩa này. ",
  "dn19:18.2": "Bạch Thế Tôn, khi Phạm thiên Sanaṅkumāra nói về ý nghĩa này, giọng nói của ngài có đầy đủ tám đặc tính: rõ ràng, dễ hiểu, dịu dàng, đáng nghe, súc tích, không lệch lạc, sâu xa, vang vọng. ",
  "dn19:18.3": "Bạch Thế Tôn, Phạm thiên Sanaṅkumāra làm cho hội chúng hiểu được bằng giọng nói của mình, âm thanh ấy không vang ra ngoài hội chúng. ",
  "dn19:18.4": "Bạch Thế Tôn, ai có giọng nói đầy đủ tám đặc tính như vậy thì được gọi là ‘có giọng Phạm thiên’. ",
  "dn19:19.1": "Rồi, bạch Thế Tôn, chư thiên cõi Ba Mươi Ba nói với Phạm thiên Sanaṅkumāra: ",
  "dn19:19.2": "‘Lành thay, Đại Phạm thiên, chúng tôi hoan hỷ khi nghĩ về điều này; ",
  "dn19:19.3": "và vua trời Đế Thích đã nói tám đức tính đúng sự thật của Thế Tôn ấy; ",
  "dn19:19.4": "chúng tôi cũng hoan hỷ khi nghĩ về những điều ấy.’ ",
  "dn19:19.5.0": "4. Tám đức tính đúng sự thật ",
  "dn19:19.6": "Rồi, bạch Thế Tôn, Phạm thiên Sanaṅkumāra nói với vua trời Đế Thích: ",
  "dn19:19.7": "‘Lành thay, vua trời Đế Thích, chúng tôi cũng xin nghe tám đức tính đúng sự thật của Thế Tôn ấy.’ ",
  "dn19:19.8": "‘Thưa vâng, Đại Phạm thiên’, bạch Thế Tôn, vua trời Đế Thích trình bày cho Phạm thiên Sanaṅkumāra nghe tám đức tính đúng sự thật của Thế Tôn. ",
  "dn19:20.1": "‘Đại Phạm thiên nghĩ thế nào? ",
  "dn19:20.2": "Thế Tôn ấy đã thực hành vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương xót thế gian, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người. ",
  "dn19:20.3": "Một bậc Đạo sư đã thực hành vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương xót thế gian, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:21.1": "Pháp được Thế Tôn ấy khéo thuyết giảng, thiết thực hiện tại, không có thời gian, đến để mà thấy, có khả năng hướng thượng, được các bậc trí tự mình chứng ngộ. ",
  "dn19:21.2": "Một bậc Đạo sư thuyết giảng Pháp có khả năng hướng thượng như vậy, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:22.1": "‘Đây là thiện’ được Thế Tôn ấy khéo chế định, ‘đây là bất thiện’ được khéo chế định, ‘đây là có tội, đây là không có tội, đây là nên thực hành, đây là không nên thực hành, đây là thấp hèn, đây là cao thượng, đây là phần đen phần trắng đối đãi’ được khéo chế định. ",
  "dn19:22.2": "Là người khéo chế định các pháp thiện, bất thiện, có tội, không có tội, nên thực hành, không nên thực hành, thấp hèn, cao thượng, phần đen phần trắng đối đãi. ",
  "dn19:22.3": "Một bậc Đạo sư đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:23.1": "Con đường đưa đến Niết-bàn cho các đệ tử được Thế Tôn ấy khéo chế định, Niết-bàn và con đường hòa quyện với nhau. ",
  "dn19:23.2": "Ví như nước sông Hằng hòa quyện, gặp nhau với nước sông Yamunā; ",
  "dn19:23.3": "cũng vậy, con đường đưa đến Niết-bàn cho các đệ tử được Thế Tôn ấy khéo chế định, Niết-bàn và con đường hòa quyện với nhau. ",
  "dn19:23.4": "Một bậc Đạo sư khéo chế định con đường đưa đến Niết-bàn như vậy, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:24.1": "Thế Tôn ấy có được lợi lộc, có được danh tiếng, các vị Sát-đế-lỵ như thể yêu mến Ngài. ",
  "dn19:24.2": "Nhưng Thế Tôn ấy dùng thức ăn mà không còn kiêu ngạo. ",
  "dn19:24.3": "Một bậc Đạo sư dùng thức ăn mà không còn kiêu ngạo như vậy, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:25.1": "Thế Tôn ấy có bạn là các bậc hữu học đang thực hành và các bậc A-la-hán đã viên thành phạm hạnh, Thế Tôn gạt họ ra một bên để sống chuyên chú vào niềm vui của sự tĩnh lặng. ",
  "dn19:25.2": "Một bậc Đạo sư chuyên chú vào niềm vui của sự tĩnh lặng như vậy, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:26.1": "Thế Tôn ấy nói sao làm vậy, làm sao nói vậy; ",
  "dn19:26.2": "như vậy là nói sao làm vậy, làm sao nói vậy. ",
  "dn19:26.3": "Một bậc Đạo sư thực hành pháp theo pháp như vậy, đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy. ",
  "dn19:27.1": "Thế Tôn ấy đã vượt qua hoài nghi, đoạn tận do dự, ý chí đã viên thành, chủ ý đã hướng về đời sống phạm hạnh căn bản. ",
  "dn19:27.2": "Một bậc Đạo sư đã vượt qua hoài nghi, đoạn tận do dự, ý chí đã viên thành, chủ ý đã hướng về đời sống phạm hạnh căn bản như vậy. ",
  "dn19:27.3": "Đầy đủ đức tính này, chúng ta không thấy ai trong quá khứ, cũng không thấy ai trong hiện tại, ngoài Thế Tôn ấy.’ ",
  "dn19:28.1": "Bạch Thế Tôn, đây là tám đức tính đúng sự thật của Thế Tôn mà vua trời Đế Thích đã trình bày cho Phạm thiên Sanaṅkumāra. ",
  "dn19:28.2": "Vì vậy, bạch Thế Tôn, Phạm thiên Sanaṅkumāra hoan hỷ, vui mừng, sinh tâm hỷ lạc sau khi nghe tám đức tính đúng sự thật của Thế Tôn. ",
  "dn19:28.3": "Rồi, bạch Thế Tôn, Phạm thiên Sanaṅkumāra sau khi tạo ra tự thân thô hơn, với hình dáng thanh niên tên Pañcasikha, xuất hiện giữa chư thiên cõi Ba Mươi Ba. ",
  "dn19:28.4": "Ngài bay lên không trung và ngồi kiết già giữa hư không. ",
  "dn19:28.5": "Ví như, bạch Thế Tôn, một người lực sĩ ngồi kiết già trên chỗ ngồi êm ái hay trên mặt đất bằng phẳng; ",
  "dn19:28.6": "cũng vậy, bạch Thế Tôn, Phạm thiên Sanaṅkumāra bay lên không trung, ngồi kiết già giữa hư không rồi nói với chư thiên cõi Ba Mươi Ba: ",
  "dn19:28.7.0": "5. Chuyện về Bà-la-môn Govinda ",
  "dn19:28.8": "‘Chư vị thiên cõi Ba Mươi Ba nghĩ thế nào, Thế Tôn ấy đã có đại trí tuệ từ rất lâu rồi. ",
  "dn19:29.1": "Thuở xưa, thưa quý vị, có vị vua tên là Disampati. ",
  "dn19:29.2": "Vua Disampati có một vị Bà-la-môn tế sư tên là Govinda. ",
  "dn19:29.3": "Vua Disampati có một người con trai tên là Hoàng tử Reṇu. ",
  "dn19:29.4": "Bà-la-môn Govinda có một người con trai, thanh niên tên là Jotipāla. ",
  "dn19:29.5": "Như vậy, Hoàng tử Reṇu, thanh niên Jotipāla và sáu vị Sát-đế-lỵ khác, tổng cộng tám người, là bạn đồng hành. ",
  "dn19:29.6": "Rồi, thưa quý vị, sau nhiều ngày đêm trôi qua, Bà-la-môn Govinda qua đời. ",
  "dn19:29.7": "Khi Bà-la-môn Govinda qua đời, vua Disampati than thở: ",
  "dn19:29.8": "‘Vào lúc mà chúng ta đã giao phó hoàn toàn mọi việc cho Bà-la-môn Govinda, và đang hưởng thụ năm dục trưởng dưỡng đầy đủ, thì Bà-la-môn Govinda của chúng ta lại qua đời.’ ",
  "dn19:29.9": "Khi được nói vậy, thưa quý vị, Hoàng tử Reṇu nói với vua Disampati: ",
  "dn19:29.10": "‘Thưa phụ vương, xin đừng quá than thở khi Bà-la-môn Govinda qua đời. ",
  "dn19:29.11": "Thưa phụ vương, Bà-la-môn Govinda có một người con trai, thanh niên tên là Jotipāla, còn thông thái hơn cha, còn biết nhiều mục đích hơn cha; ",
  "dn19:29.12": "những việc mà cha cậu ấy đã chỉ dạy, đều là do thanh niên Jotipāla chỉ dạy.’ ",
  "dn19:29.13": "‘Đúng vậy chăng, con?’ ",
  "dn19:29.14": "‘Đúng vậy, thưa phụ vương.’ ",
  "dn19:30.0": "6. Chuyện về Đại Điển Tôn ",
  "dn19:30.1": "Rồi, thưa quý vị, vua Disampati gọi một người nọ: ",
  "dn19:30.2": "‘Này người kia, hãy đi đến chỗ thanh niên Jotipāla; sau khi đến, hãy nói với thanh niên Jotipāla như vầy: ",
  "dn19:30.3": "“Xin chào Tôn giả Jotipāla, vua Disampati cho mời Tôn giả Jotipāla, vua Disampati muốn gặp Tôn giả Jotipāla.”’ ",
  "dn19:30.4": "‘Thưa vâng, đại vương’, thưa quý vị, người ấy vâng lời vua Disampati, đi đến chỗ thanh niên Jotipāla; sau khi đến, nói với thanh niên Jotipāla rằng: ",
  "dn19:30.5": "‘Xin chào Tôn giả Jotipāla, vua Disampati cho mời Tôn giả Jotipāla, vua Disampati muốn gặp Tôn giả Jotipāla.’ ",
  "dn19:30.6": "‘Thưa vâng, thưa ngài’, thưa quý vị, thanh niên Jotipāla vâng lời người ấy, đi đến chỗ vua Disampati; sau khi đến, chào hỏi vua Disampati; ",
  "dn19:30.7": "sau khi nói lên những lời chào hỏi thân thiện đáng nhớ, ngồi xuống một bên. Khi thanh niên Jotipāla đã ngồi xuống một bên, thưa quý vị, vua Disampati nói với thanh niên Jotipāla: ",
  "dn19:30.8": "‘Xin Tôn giả Jotipāla hãy chỉ dạy chúng ta, xin Tôn giả Jotipāla đừng từ chối lời chỉ dạy. ",
  "dn19:30.9": "Ta sẽ đặt ngài vào chức vị của cha ngài, làm lễ quán đảnh phong ngài làm tế sư.’ ",
  "dn19:30.10": "‘Thưa vâng, thưa ngài’, thưa quý vị, thanh niên Jotipāla vâng lời vua Disampati. ",
  "dn19:31.1": "Rồi, thưa quý vị, vua Disampati làm lễ quán đảnh phong thanh niên Jotipāla làm tế sư, đặt ngài vào chức vị của cha ngài. ",
  "dn19:31.2": "Sau khi được làm lễ quán đảnh phong tế sư, được đặt vào chức vị của cha, thanh niên Jotipāla chỉ dạy những việc mà cha đã chỉ dạy, và cũng chỉ dạy những việc mà cha chưa chỉ dạy; ",
  "dn19:31.3": "hoàn thành những công việc mà cha đã hoàn thành, và cũng hoàn thành những công việc mà cha chưa hoàn thành. ",
  "dn19:31.4": "Dân chúng nói về cậu ấy rằng: ",
  "dn19:31.5": "‘Ôi, quý vị, Bà-la-môn này thật là Govinda, ôi quý vị, Bà-la-môn này thật là Đại Govinda (Mahāgovinda).’ ",
  "dn19:31.6": "Theo cách này, thưa quý vị, tên gọi ‘Govinda, Đại Govinda’ đã xuất hiện đối với thanh niên Jotipāla. ",
  "dn19:32.0": "6.1. Phân chia vương quốc ",
  "dn19:32.1": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda đi đến chỗ sáu vị Sát-đế-lỵ; sau khi đến, nói với sáu vị Sát-đế-lỵ: ",
  "dn19:32.2": "‘Thưa quý vị, vua Disampati đã già, đã lớn tuổi, cao niên, đã sống lâu năm, đã đến cuối đời, ai biết được mạng sống? ",
  "dn19:32.3": "Có thể khi vua Disampati qua đời, những người làm vua sẽ phong Hoàng tử Reṇu lên ngôi vua. ",
  "dn19:32.4": "Quý vị hãy đến gặp Hoàng tử Reṇu; sau khi đến, hãy nói với Hoàng tử Reṇu rằng: ",
  "dn19:32.5": "‘Chúng tôi là bạn thân yêu quý của Tôn giả Reṇu, không xa lánh, Tôn giả hạnh phúc thì chúng tôi hạnh phúc, Tôn giả khổ thì chúng tôi khổ. ",
  "dn19:32.6": "Thưa quý vị, vua Disampati đã già, đã lớn tuổi, cao niên, đã sống lâu năm, đã đến cuối đời, ai biết được mạng sống? ",
  "dn19:32.7": "Có thể khi vua Disampati qua đời, những người làm vua sẽ phong Tôn giả Reṇu lên ngôi vua. ",
  "dn19:32.8": "Nếu Tôn giả Reṇu được ngôi vua, xin hãy chia sẻ vương quốc với chúng tôi.’” ",
  "dn19:33.1": "‘Thưa vâng, thưa ngài’, thưa quý vị, sáu vị Sát-đế-lỵ ấy vâng lời Bà-la-môn Đại Govinda, đi đến chỗ Hoàng tử Reṇu; sau khi đến, nói với Hoàng tử Reṇu: ",
  "dn19:33.2": "‘Chúng tôi là bạn thân yêu quý của Tôn giả Reṇu, không xa lánh; ",
  "dn19:33.3": "Tôn giả hạnh phúc thì chúng tôi hạnh phúc, Tôn giả khổ thì chúng tôi khổ. ",
  "dn19:33.4": "Thưa ngài, vua Disampati đã già, đã lớn tuổi, cao niên, đã sống lâu năm, đã đến cuối đời, ai biết được mạng sống? ",
  "dn19:33.5": "Có thể khi vua Disampati qua đời, những người làm vua sẽ phong Tôn giả Reṇu lên ngôi vua. ",
  "dn19:33.6": "Nếu Tôn giả Reṇu được ngôi vua, xin hãy chia sẻ vương quốc với chúng tôi.’ ",
  "dn19:33.7": "‘Thưa quý vị, ngoài các tôn giả ra, còn ai khác sẽ hạnh phúc trong lãnh thổ của tôi? ",
  "dn19:33.8": "Nếu tôi được ngôi vua, tôi sẽ chia sẻ vương quốc với quý vị.’ ",
  "dn19:34.1": "Rồi, thưa quý vị, sau nhiều ngày đêm trôi qua, vua Disampati qua đời. ",
  "dn19:34.2": "Khi vua Disampati qua đời, những người làm vua phong Hoàng tử Reṇu lên ngôi vua. ",
  "dn19:34.3": "Sau khi được phong làm vua, Reṇu được hưởng thụ năm dục trưởng dưỡng đầy đủ. ",
  "dn19:34.4": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda đi đến chỗ sáu vị Sát-đế-lỵ; sau khi đến, nói với sáu vị Sát-đế-lỵ: ",
  "dn19:34.5": "‘Thưa quý vị, vua Disampati đã qua đời. ",
  "dn19:34.6": "Sau khi được phong làm vua, Reṇu đang hưởng thụ năm dục trưởng dưỡng đầy đủ. ",
  "dn19:34.7": "Thưa quý vị, ai biết được, các dục lạc làm cho say mê? ",
  "dn19:34.8": "Quý vị hãy đến gặp vua Reṇu; sau khi đến, hãy nói với vua Reṇu rằng: ",
  "dn19:34.9": "‘Thưa ngài, vua Disampati đã qua đời, Tôn giả Reṇu đã được phong làm vua, Tôn giả có nhớ lời nói ấy không?’” ",
  "dn19:34.10": "‘Thưa vâng, thưa ngài’, thưa quý vị, sáu vị Sát-đế-lỵ ấy vâng lời Bà-la-môn Đại Govinda, đi đến chỗ vua Reṇu; sau khi đến, nói với vua Reṇu rằng: ",
  "dn19:34.11": "‘Thưa ngài, vua Disampati đã qua đời, Tôn giả Reṇu đã được phong làm vua, Tôn giả có nhớ lời nói ấy không?’ ",
  "dn19:34.12": "‘Tôi nhớ lời nói ấy, thưa quý vị. ",
  "dn19:34.13": "Thưa quý vị, ai có thể chia đất lớn này, trải dài về hướng bắc, có dạng như miệng xe bò về hướng nam, thành bảy phần đều nhau, khéo chia?’ ",
  "dn19:34.14": "‘Thưa ngài, ai có thể làm được ngoài Bà-la-môn Đại Govinda?’ ",
  "dn19:35.1": "Rồi, thưa quý vị, vua Reṇu gọi một người nọ: ",
  "dn19:35.2": "‘Này người kia, hãy đi đến chỗ Bà-la-môn Đại Govinda; sau khi đến, hãy nói với Bà-la-môn Đại Govinda như vầy: ",
  "dn19:35.3": "‘Thưa ngài, vua Reṇu cho mời ngài.’” ",
  "dn19:35.4": "‘Thưa vâng, đại vương’, thưa quý vị, người ấy vâng lời vua Reṇu, đi đến chỗ Bà-la-môn Đại Govinda; sau khi đến, nói với Bà-la-môn Đại Govinda rằng: ",
  "dn19:35.5": "‘Thưa ngài, vua Reṇu cho mời ngài.’ ",
  "dn19:35.6": "‘Thưa vâng, thưa ngài’, thưa quý vị, Bà-la-môn Đại Govinda vâng lời người ấy, đi đến chỗ vua Reṇu; sau khi đến, chào hỏi vua Reṇu. ",
  "dn19:35.7": "Sau khi nói lên những lời chào hỏi thân thiện đáng nhớ, ngồi xuống một bên. Khi Bà-la-môn Đại Govinda đã ngồi xuống một bên, thưa quý vị, vua Reṇu nói với Bà-la-môn Đại Govinda: ",
  "dn19:35.8": "‘Xin Tôn giả Govinda hãy chia đất lớn này, trải dài về hướng bắc, có dạng như miệng xe bò về hướng nam, thành bảy phần đều nhau, khéo chia.’ ",
  "dn19:35.9": "‘Thưa vâng, thưa ngài’, thưa quý vị, Bà-la-môn Đại Govinda vâng lời vua Reṇu, chia đất lớn này, trải dài về hướng bắc, có dạng như miệng xe bò về hướng nam, thành bảy phần đều nhau, khéo chia. ",
  "dn19:36.1": "Tất cả đều có dạng như miệng xe bò được sắp đặt. ",
  "dn19:36.2": "Ở giữa là lãnh thổ của vua Reṇu. ",
  "dn19:36.3": "Dantapura của dân Kaliṅga, ",
  "dn19:36.4": "Potana của dân Assaka; ",
  "dn19:36.5": "Mahissati của dân Avantī, ",
  "dn19:36.6": "Roruka của dân Sovīra. ",
  "dn19:36.7": "Mithilā của dân Videha, ",
  "dn19:36.8": "Campā được xây dựng ở xứ Aṅga; ",
  "dn19:36.9": "Bārāṇasī của dân Kāsī, ",
  "dn19:36.10": "Đó là những nơi do Govinda xây dựng. ",
  "dn19:36.11": "Rồi, thưa quý vị, sáu vị Sát-đế-lỵ ấy hài lòng với phần được của mình, ước nguyện đã viên mãn: ",
  "dn19:36.12": "‘Điều ta đã mong muốn, đã khát khao, đã mong mỏi, đã ao ước, đã được ban cho chúng ta.’ ",
  "dn19:36.13": "Sattabhū và Brahmadatta, ",
  "dn19:36.14": "Vessabhū và Bharata; ",
  "dn19:36.15": "Reṇu cùng hai vị Dhataraṭṭha, ",
  "dn19:36.16": "Lúc ấy là bảy vị Bhārata. ",
  "dn19:36.17": "Hết tụng phần thứ nhất. ",
  "dn19:37.0": "6.2. Tiếng đồn vang xa ",
  "dn19:37.1": "Rồi, thưa quý vị, sáu vị Sát-đế-lỵ ấy đi đến chỗ Bà-la-môn Đại Govinda; sau khi đến, nói với Bà-la-môn Đại Govinda: ",
  "dn19:37.2": "‘Như Tôn giả Govinda là bạn thân yêu quý, không xa lánh của vua Reṇu. ",
  "dn19:37.3": "Cũng vậy, Tôn giả Govinda cũng là bạn thân yêu quý, không xa lánh của chúng tôi, xin Tôn giả Govinda hãy chỉ dạy chúng tôi; ",
  "dn19:37.4": "xin Tôn giả Govinda đừng từ chối lời chỉ dạy.’ ",
  "dn19:37.5": "‘Thưa vâng, thưa ngài’, Bà-la-môn Đại Govinda vâng lời sáu vị Sát-đế-lỵ ấy. ",
  "dn19:37.6": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda chỉ dạy cho bảy vị vua Sát-đế-lỵ đã làm lễ quán đảnh về việc trị vì, và dạy chú thuật cho bảy đại Bà-la-môn và bảy trăm thanh niên đã tắm gội. ",
  "dn19:38.1": "Rồi, thưa quý vị, về sau tiếng đồn tốt đẹp sau đây về Bà-la-môn Đại Govinda đã lan truyền: ",
  "dn19:38.2": "‘Bà-la-môn Đại Govinda tận mắt thấy Phạm thiên, Bà-la-môn Đại Govinda đàm đạo, trò chuyện, bàn bạc với Phạm thiên.’ ",
  "dn19:38.3": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda khởi lên ý nghĩ: ",
  "dn19:38.4": "‘Tiếng đồn tốt đẹp sau đây về ta đã lan truyền: ",
  "dn19:38.5": "‘Bà-la-môn Đại Govinda tận mắt thấy Phạm thiên, Bà-la-môn Đại Govinda đàm đạo, trò chuyện, bàn bạc với Phạm thiên.’ ",
  "dn19:38.6": "Nhưng ta không thấy Phạm thiên, không đàm đạo với Phạm thiên, không trò chuyện với Phạm thiên, không bàn bạc với Phạm thiên. ",
  "dn19:38.7": "Ta có nghe các Bà-la-môn trưởng lão, lớn tuổi, thầy của thầy nói rằng: ",
  "dn19:38.8": "‘Ai sống ẩn cư bốn tháng mùa mưa, thực hành thiền bi, thì thấy được Phạm thiên, đàm đạo với Phạm thiên, trò chuyện với Phạm thiên, bàn bạc với Phạm thiên.’ ",
  "dn19:38.9": "Vậy ta hãy sống ẩn cư bốn tháng mùa mưa, thực hành thiền bi.’ ",
  "dn19:39.1": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda đi đến chỗ vua Reṇu; sau khi đến, nói với vua Reṇu: ",
  "dn19:39.2": "‘Thưa ngài, tiếng đồn tốt đẹp sau đây về tôi đã lan truyền: ",
  "dn19:39.3": "‘Bà-la-môn Đại Govinda tận mắt thấy Phạm thiên, Bà-la-môn Đại Govinda đàm đạo, trò chuyện, bàn bạc với Phạm thiên.’ ",
  "dn19:39.4": "Thưa ngài, nhưng tôi không thấy Phạm thiên, không đàm đạo với Phạm thiên, không trò chuyện với Phạm thiên, không bàn bạc với Phạm thiên. ",
  "dn19:39.5": "Tôi có nghe các Bà-la-môn trưởng lão, lớn tuổi, thầy của thầy nói rằng: ",
  "dn19:39.6": "‘Ai sống ẩn cư bốn tháng mùa mưa, thực hành thiền bi, thì thấy được Phạm thiên, đàm đạo với Phạm thiên, trò chuyện với Phạm thiên, bàn bạc với Phạm thiên.’ ",
  "dn19:39.7": "Thưa ngài, tôi muốn sống ẩn cư bốn tháng mùa mưa, thực hành thiền bi; ",
  "dn19:39.8": "không ai được đến thăm tôi ngoại trừ một người đem bữa ăn.’ ",
  "dn19:39.9": "‘Tôn giả Govinda hãy tùy ý làm lúc ngài thấy thích hợp.’ ",
  "dn19:40.1": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda đi đến chỗ sáu vị Sát-đế-lỵ; sau khi đến, nói với sáu vị Sát-đế-lỵ: ",
  "dn19:40.2": "‘Thưa quý vị, tiếng đồn tốt đẹp sau đây về tôi đã lan truyền: ",
  "dn19:40.3": "‘Bà-la-môn Đại Govinda tận mắt thấy Phạm thiên, Bà-la-môn Đại Govinda đàm đạo, trò chuyện, bàn bạc với Phạm thiên.’ ",
  "dn19:40.4": "Thưa quý vị, nhưng tôi không thấy Phạm thiên, không đàm đạo với Phạm thiên, không trò chuyện với Phạm thiên, không bàn bạc với Phạm thiên. ",
  "dn19:40.5": "Tôi có nghe các Bà-la-môn trưởng lão, lớn tuổi, thầy của thầy nói rằng: ",
  "dn19:40.6": "‘Ai sống ẩn cư bốn tháng mùa mưa, thực hành thiền bi, thì thấy được Phạm thiên, đàm đạo với Phạm thiên, trò chuyện với Phạm thiên, bàn bạc với Phạm thiên.’ ",
  "dn19:40.7": "Thưa quý vị, tôi muốn sống ẩn cư bốn tháng mùa mưa, thực hành thiền bi; ",
  "dn19:40.8": "không ai được đến thăm tôi ngoại trừ một người đem bữa ăn.’ ",
  "dn19:40.9": "‘Tôn giả Govinda hãy tùy ý làm lúc ngài thấy thích hợp.’ ",
  "dn19:41.1": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda đi đến chỗ bảy đại Bà-la-môn và bảy trăm thanh niên đã tắm gội; sau khi đến, nói với bảy đại Bà-la-môn và bảy trăm thanh niên đã tắm gội: ",
  "dn19:41.2": "‘Thưa quý vị, tiếng đồn tốt đẹp sau đây về tôi đã lan truyền: ",
  "dn19:41.3": "‘Bà-la-môn Đại Govinda tận mắt thấy Phạm thiên, Bà-la-môn Đại Govinda đàm đạo, trò chuyện, bàn bạc với Phạm thiên.’ ",
  "dn19:41.4": "Thưa quý vị, nhưng tôi không thấy Phạm thiên, không đàm đạo với Phạm thiên, không trò chuyện với Phạm thiên, không bàn bạc với Phạm thiên. ",
  "dn19:41.5": "Tôi có nghe các Bà-la-môn trưởng lão, lớn tuổi, thầy của thầy nói rằng: ",
  "dn19:41.6": "‘Ai sống ẩn cư bốn tháng mùa mưa, thực hành thiền bi, thì thấy được Phạm thiên, đàm đạo với Phạm thiên, trò chuyện với Phạm thiên, bàn bạc với Phạm thiên.’ ",
  "dn19:41.7": "Vậy thưa quý vị, hãy tụng đọc kỹ lưỡng các chú thuật đã nghe, đã học, và dạy chú thuật cho nhau; ",
  "dn19:41.8": "thưa quý vị, tôi muốn sống ẩn cư bốn tháng mùa mưa, thực hành thiền bi; ",
  "dn19:41.9": "không ai được đến thăm tôi ngoại trừ một người đem bữa ăn.’ ",
  "dn19:41.10": "‘Tôn giả Govinda hãy tùy ý làm lúc ngài thấy thích hợp.’ ",
  "dn19:42.1": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda đi đến chỗ bốn mươi người vợ cùng dòng dõi; sau khi đến, nói với bốn mươi người vợ cùng dòng dõi: ",
  "dn19:42.2": "‘Các bà, tiếng đồn tốt đẹp sau đây về tôi đã lan truyền: ",
  "dn19:42.3": "‘Bà-la-môn Đại Govinda tận mắt thấy Phạm thiên, Bà-la-môn Đại Govinda đàm đạo, trò chuyện, bàn bạc với Phạm thiên.’ ",
  "dn19:42.4": "Các bà, nhưng tôi không thấy Phạm thiên, không đàm đạo với Phạm thiên, không trò chuyện với Phạm thiên, không bàn bạc với Phạm thiên. ",
  "dn19:42.5": "Tôi có nghe các Bà-la-môn trưởng lão, lớn tuổi, thầy của thầy nói rằng: ",
  "dn19:42.6": "‘Ai sống ẩn cư bốn tháng mùa mưa, thực hành thiền bi, thì thấy được Phạm thiên, đàm đạo với Phạm thiên, trò chuyện với Phạm thiên, bàn bạc với Phạm thiên.’ ",
  "dn19:42.7": "Các bà, tôi muốn sống ẩn cư bốn tháng mùa mưa, thực hành thiền bi; ",
  "dn19:42.8": "không ai được đến thăm tôi ngoại trừ một người đem bữa ăn.’ ",
  "dn19:42.9": "‘Tôn giả Govinda hãy tùy ý làm lúc ngài thấy thích hợp.’ ",
  "dn19:43.1": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda cho xây một trai phòng mới ở phía đông thành, sống ẩn cư bốn tháng mùa mưa, thực hành thiền bi; ",
  "dn19:43.2": "không ai đến gần ngoại trừ một người đem bữa ăn. ",
  "dn19:43.3": "Rồi, thưa quý vị, sau bốn tháng trôi qua, Bà-la-môn Đại Govinda sinh ra sự bất mãn, sự lo lắng: ",
  "dn19:43.4": "‘Tôi có nghe các Bà-la-môn trưởng lão, lớn tuổi, thầy của thầy nói rằng: ",
  "dn19:43.5": "‘Ai sống ẩn cư bốn tháng mùa mưa, thực hành thiền bi, thì thấy được Phạm thiên, đàm đạo với Phạm thiên, trò chuyện với Phạm thiên, bàn bạc với Phạm thiên.’ ",
  "dn19:43.6": "Nhưng ta không thấy Phạm thiên, không đàm đạo với Phạm thiên, không trò chuyện với Phạm thiên, không bàn bạc với Phạm thiên.’ ",
  "dn19:44.0": "6.3. Đàm đạo với Phạm thiên ",
  "dn19:44.1": "Rồi, thưa quý vị, Phạm thiên Sanaṅkumāra với tâm mình biết được suy nghĩ trong tâm của Bà-la-môn Đại Govinda—ví như một người lực sĩ co duỗi cánh tay, hay duỗi co cánh tay; cũng vậy—biến mất khỏi cõi Phạm thiên và xuất hiện trước mặt Bà-la-môn Đại Govinda. ",
  "dn19:44.2": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda cảm thấy sợ hãi, kinh hoảng, lông dựng đứng khi thấy hình sắc chưa từng thấy trước đây. ",
  "dn19:44.3": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda sợ hãi, hoảng hốt, lông dựng đứng, nói với Phạm thiên Sanaṅkumāra bằng bài kệ: ",
  "dn19:44.4": "‘Có dung sắc, có danh tiếng, có uy lực, ",
  "dn19:44.5": "Thưa ngài, ngài là ai? ",
  "dn19:44.6": "Không biết nên tôi xin hỏi, ",
  "dn19:44.7": "Làm sao chúng tôi biết được ngài?’ ",
  "dn19:44.8": "‘Ta là bậc vĩnh hằng, ",
  "dn19:44.9": "Được biết ở cõi Phạm thiên; ",
  "dn19:44.10": "Tất cả chư thiên đều biết ta, ",
  "dn19:44.11": "Này Govinda, hãy biết như vậy.’ ",
  "dn19:44.12": "‘Chỗ ngồi, nước, thức ăn, ",
  "dn19:44.13": "Cùng món mật cho Phạm thiên; ",
  "dn19:44.14": "Tôi xin hỏi tôn giả về lễ vật, ",
  "dn19:44.15": "Xin tôn giả nhận lễ vật của tôi.’ ",
  "dn19:44.16": "‘Ta nhận lễ vật của ông, ",
  "dn19:44.17": "Điều mà ông, Govinda, đã nói; ",
  "dn19:44.18": "Vì lợi ích trong đời này, ",
  "dn19:44.19": "Và hạnh phúc trong đời sau; ",
  "dn19:44.20": "Hãy tận dụng cơ hội mà hỏi, ",
  "dn19:44.21": "Bất cứ điều gì ông mong muốn.’ ",
  "dn19:45.1": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda khởi lên ý nghĩ: ",
  "dn19:45.2": "‘Ta đã được Phạm thiên Sanaṅkumāra cho cơ hội. ",
  "dn19:45.3": "Vậy ta nên hỏi Phạm thiên Sanaṅkumāra về lợi ích đời này hay lợi ích đời sau?’ ",
  "dn19:45.4": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda khởi lên ý nghĩ: ",
  "dn19:45.5": "‘Ta thiện xảo về các lợi ích đời này, người khác cũng hỏi ta về lợi ích đời này. ",
  "dn19:45.6": "Vậy ta nên hỏi Phạm thiên Sanaṅkumāra chỉ về lợi ích đời sau.’ ",
  "dn19:45.7": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda nói với Phạm thiên Sanaṅkumāra bằng bài kệ: ",
  "dn19:45.8": "‘Tôi xin hỏi Phạm thiên Sanaṅkumāra, ",
  "dn19:45.9": "Kẻ nghi ngờ hỏi bậc không nghi về điều người khác biết; ",
  "dn19:45.10": "Đứng ở đâu, tu tập điều gì, ",
  "dn19:45.11": "Người phàm đạt đến cõi Phạm thiên bất tử?’ ",
  "dn19:45.12": "‘Này Phạm chí, hãy từ bỏ sự chiếm hữu giữa loài người, ",
  "dn19:45.13": "Chỉ một mình, chú tâm vào bi; ",
  "dn19:45.14": "Không có mùi thịt, tránh xa dâm dục, ",
  "dn19:45.15": "Đứng ở đây và tu tập ở đây; ",
  "dn19:45.16": "Người phàm đạt đến cõi Phạm thiên bất tử.’ ",
  "dn19:46.1": "‘‘Từ bỏ sự chiếm hữu’, tôi hiểu lời của ngài. ",
  "dn19:46.2": "Ở đây có người từ bỏ tài sản nhỏ hay từ bỏ tài sản lớn, từ bỏ gia tộc nhỏ hay từ bỏ gia tộc lớn, cạo bỏ râu tóc, mặc y áo cà-sa, xuất gia từ bỏ đời sống gia đình để sống đời không nhà, ",
  "dn19:46.3": "như vậy ‘từ bỏ sự chiếm hữu’, tôi hiểu lời của ngài. ",
  "dn19:46.4": "‘Chỉ một mình’, tôi hiểu lời của ngài. ",
  "dn19:46.5": "Ở đây có người tìm đến trú xứ vắng lặng: rừng, gốc cây, núi, hang đá, vách đá, nghĩa địa, rừng rậm, chỗ trống, đống rơm, ",
  "dn19:46.6": "như vậy ‘chỉ một mình’, tôi hiểu lời của ngài. ",
  "dn19:46.7": "‘Chú tâm vào bi’, tôi hiểu lời của ngài. ",
  "dn19:46.8": "Ở đây có người an trú, biến mãn một phương với tâm câu hữu với bi, cũng vậy với phương thứ hai, phương thứ ba, phương thứ tư. Như vậy, cùng khắp trên, dưới, ngang, và ở mọi nơi, đối với tất cả, cũng như đối với chính mình, an trú, biến mãn khắp thế giới với tâm câu hữu với bi, rộng lớn, quảng đại, vô lượng, không thù hận, không sân hận. ",
  "dn19:46.9": "Như vậy ‘chú tâm vào bi’, tôi hiểu lời của ngài. ",
  "dn19:46.10": "Thưa tôn giả, tôi không hiểu ‘mùi thịt’ khi ngài nói. ",
  "dn19:46.11": "‘Thưa ngài Phạm thiên, mùi thịt giữa loài người là gì, ",
  "dn19:46.12": "Những điều đó tôi không biết, xin bậc trí nói cho tôi; ",
  "dn19:46.13": "Bị che lấp bởi gì mà chúng sinh, ",
  "dn19:46.14": "Bị ô nhiễm bởi điều gì, đi vào ác thú, bị ngăn chặn khỏi cõi Phạm thiên?’ ",
  "dn19:46.15": "‘Giận, nói dối, lừa dối, phản bội, ",
  "dn19:46.16": "Bủn xỉn, kiêu ngạo, ghen tị; ",
  "dn19:46.17": "Ham muốn, nghi ngờ, hại người, ",
  "dn19:46.18": "Tham, sân, ngạo, si; ",
  "dn19:46.19": "Dính vào những thứ này thì có mùi thịt, ",
  "dn19:46.20": "Đi vào ác thú, bị ngăn chặn khỏi cõi Phạm thiên.’ ",
  "dn19:46.21": "‘Thưa tôn giả, khi nghe ngài nói về ‘mùi thịt’, tôi hiểu rằng chúng không dễ bị diệt đối với người sống tại gia. ",
  "dn19:46.22": "Thưa ngài, tôi sẽ xuất gia từ bỏ gia đình sống đời không nhà.’ ",
  "dn19:46.23": "‘Tôn giả Govinda hãy tùy ý làm lúc ngài thấy thích hợp.’ ",
  "dn19:47.0": "6.4. Bẩm báo vua Reṇu ",
  "dn19:47.1": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda đi đến chỗ vua Reṇu; sau khi đến, nói với vua Reṇu: ",
  "dn19:47.2": "‘Nay xin ngài hãy tìm một vị tế sư khác để chỉ dạy việc trị vì cho ngài. ",
  "dn19:47.3": "Thưa ngài, tôi muốn xuất gia từ bỏ gia đình sống đời không nhà. ",
  "dn19:47.4": "Theo lời tôi nghe Phạm thiên nói về ‘mùi thịt’, chúng không dễ bị diệt đối với người sống tại gia. ",
  "dn19:47.5": "Thưa ngài, tôi sẽ xuất gia từ bỏ gia đình sống đời không nhà.’ ",
  "dn19:47.6": "‘Tôi thưa với nhà vua, ",
  "dn19:47.7": "Với vua Reṇu chủ đất; ",
  "dn19:47.8": "Ngài hãy trị vì với vương quốc, ",
  "dn19:47.9": "Còn tôi không thích chức tế sư.’ ",
  "dn19:47.10": "‘Nếu ngài thiếu gì trong các dục lạc, ",
  "dn19:47.11": "Ta sẽ cung cấp đầy đủ cho ngài; ",
  "dn19:47.12": "Ai hại ngài, ta sẽ ngăn, ",
  "dn19:47.13": "Ta là tướng quân của đất nước; ",
  "dn19:47.14": "Ngài là cha, ta là con, ",
  "dn19:47.15": "Govinda, xin đừng bỏ chúng ta.’ ",
  "dn19:47.16": "‘Tôi không thiếu gì trong các dục lạc, ",
  "dn19:47.17": "Không có ai hại tôi cả; ",
  "dn19:47.18": "Sau khi nghe lời phi nhân, ",
  "dn19:47.19": "Nên tôi không còn thích gia đình.’ ",
  "dn19:47.20": "‘Phi nhân ấy có dung sắc thế nào, ",
  "dn19:47.21": "Đã nói với ngài điều gì; ",
  "dn19:47.22": "Nghe xong mà ngài bỏ, ",
  "dn19:47.23": "Tất cả chúng tôi và gia đình?’ ",
  "dn19:47.24": "‘Khi tôi đã giữ giới trước đó, ",
  "dn19:47.25": "Đang muốn cử hành lễ tế; ",
  "dn19:47.26": "Lửa đã được đốt lên, ",
  "dn19:47.27": "Cỏ kusa đã được rải ra. ",
  "dn19:47.28": "Rồi Phạm thiên hiện ra cho tôi, ",
  "dn19:47.29": "Bậc vĩnh hằng từ cõi Phạm thiên; ",
  "dn19:47.30": "Ngài đã trả lời câu hỏi của tôi, ",
  "dn19:47.31": "Nghe xong tôi không còn thích gia đình.’ ",
  "dn19:47.32": "‘Tôi tin lời ngài, ",
  "dn19:47.33": "Điều mà Tôn giả Govinda nói; ",
  "dn19:47.34": "Sau khi nghe lời phi nhân, ",
  "dn19:47.35": "Làm sao ngài hành xử khác được. ",
  "dn19:47.36": "Chúng tôi sẽ theo ngài, ",
  "dn19:47.37": "Govinda là thầy của chúng tôi; ",
  "dn19:47.38": "Như viên ngọc lưu ly, ",
  "dn19:47.39": "Không tì vết, trong sạch, đẹp đẽ; ",
  "dn19:47.40": "Chúng tôi cũng sẽ sống trong sạch như vậy, ",
  "dn19:47.41": "Theo lời chỉ dạy của Govinda. ",
  "dn19:47.42": "Nếu Tôn giả Govinda xuất gia từ bỏ gia đình sống đời không nhà, thì chúng tôi cũng xuất gia từ bỏ gia đình sống đời không nhà. ",
  "dn19:47.43": "Cảnh giới nào của ngài, cảnh giới ấy cũng sẽ là của chúng tôi.’ ",
  "dn19:48.0": "6.5. Bẩm báo sáu vị Sát-đế-lỵ ",
  "dn19:48.1": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda đi đến chỗ sáu vị Sát-đế-lỵ; sau khi đến, nói với sáu vị Sát-đế-lỵ: ",
  "dn19:48.2": "‘Nay xin quý vị hãy tìm một vị tế sư khác để chỉ dạy việc trị vì cho quý vị. ",
  "dn19:48.3": "Thưa quý vị, tôi muốn xuất gia từ bỏ gia đình sống đời không nhà. ",
  "dn19:48.4": "Theo lời tôi nghe Phạm thiên nói về ‘mùi thịt’, chúng không dễ bị diệt đối với người sống tại gia. ",
  "dn19:48.5": "Thưa quý vị, tôi sẽ xuất gia từ bỏ gia đình sống đời không nhà.’ ",
  "dn19:49.1": "Rồi, thưa quý vị, sáu vị Sát-đế-lỵ ấy đi qua một bên và cùng suy nghĩ: ",
  "dn19:49.2": "‘Các Bà-la-môn này hám tiền; ",
  "dn19:49.3": "vậy chúng ta hãy dụ Bà-la-môn Đại Govinda bằng tiền.’ ",
  "dn19:49.4": "Họ đi đến Bà-la-môn Đại Govinda và nói rằng: ",
  "dn19:49.5": "‘Thưa ngài, trong bảy vương quốc này có rất nhiều tài sản; ngài cần bao nhiêu, chúng tôi sẽ đem tới bấy nhiêu.’ ",
  "dn19:49.6": "‘Thôi, quý vị, tôi đã có nhiều tài sản nhờ quý vị. ",
  "dn19:49.7": "Tôi sẽ từ bỏ tất cả mà xuất gia từ bỏ gia đình sống đời không nhà. ",
  "dn19:49.8": "Theo lời tôi nghe Phạm thiên nói về ‘mùi thịt’, chúng không dễ bị diệt đối với người sống tại gia, ",
  "dn19:49.9": "thưa quý vị, tôi sẽ xuất gia từ bỏ gia đình sống đời không nhà.’ ",
  "dn19:49.10": "Rồi, thưa quý vị, sáu vị Sát-đế-lỵ ấy đi qua một bên và cùng suy nghĩ: ",
  "dn19:49.11": "‘Các Bà-la-môn này hám phụ nữ; ",
  "dn19:49.12": "vậy chúng ta hãy dụ Bà-la-môn Đại Govinda bằng phụ nữ.’ ",
  "dn19:49.13": "Họ đi đến Bà-la-môn Đại Govinda và nói rằng: ",
  "dn19:49.14": "‘Thưa ngài, trong bảy vương quốc này có rất nhiều phụ nữ; ngài cần bao nhiêu, chúng tôi sẽ đem tới bấy nhiêu.’ ",
  "dn19:49.15": "‘Thôi, quý vị, tôi đã có bốn mươi người vợ cùng dòng dõi. ",
  "dn19:49.16": "Tôi sẽ từ bỏ tất cả các bà ấy mà xuất gia từ bỏ gia đình sống đời không nhà. ",
  "dn19:49.17": "Theo lời tôi nghe Phạm thiên nói về ‘mùi thịt’, chúng không dễ bị diệt đối với người sống tại gia, ",
  "dn19:49.18": "thưa quý vị, tôi sẽ xuất gia từ bỏ gia đình sống đời không nhà.’ ",
  "dn19:50.1": "‘Nếu Tôn giả Govinda xuất gia từ bỏ gia đình sống đời không nhà, thì chúng tôi cũng xuất gia từ bỏ gia đình sống đời không nhà; cảnh giới nào của ngài, cảnh giới ấy cũng sẽ là của chúng tôi.’ ",
  "dn19:50.2": "‘Nếu quý vị từ bỏ các dục, ",
  "dn19:50.3": "Nơi kẻ phàm phu dính mắc; ",
  "dn19:50.4": "Hãy tinh tấn, hãy kiên cường, ",
  "dn19:50.5": "Đầy đủ sức mạnh nhẫn nại. ",
  "dn19:50.6": "Đây là con đường ngay thẳng, ",
  "dn19:50.7": "Đây là con đường tối thượng; ",
  "dn19:50.8": "Chánh pháp được bậc thiện hộ trì, ",
  "dn19:50.9": "Để tái sinh vào cõi Phạm thiên.’ ",
  "dn19:51.1": "‘Vậy thì Tôn giả Govinda hãy chờ bảy năm. ",
  "dn19:51.2": "Sau bảy năm, chúng tôi cũng sẽ xuất gia từ bỏ gia đình sống đời không nhà; cảnh giới nào của ngài, cảnh giới ấy cũng sẽ là của chúng tôi.’ ",
  "dn19:51.3": "‘Thưa quý vị, bảy năm quá lâu, tôi không thể chờ quý vị bảy năm. ",
  "dn19:51.4": "Thưa quý vị, ai biết được mạng sống. ",
  "dn19:51.5": "Cần phải đi đến đời sau, cần phải suy xét bằng trí tuệ, cần phải làm việc thiện, cần phải sống đời phạm hạnh, không có người sinh ra mà không chết. ",
  "dn19:51.6": "Theo lời tôi nghe Phạm thiên nói về ‘mùi thịt’, chúng không dễ bị diệt đối với người sống tại gia, ",
  "dn19:51.7": "thưa quý vị, tôi sẽ xuất gia từ bỏ gia đình sống đời không nhà.’ ",
  "dn19:52.1": "‘Vậy thì Tôn giả Govinda hãy chờ sáu năm …(v.v.)… ",
  "dn19:52.2": "hãy chờ năm năm … ",
  "dn19:52.3": "hãy chờ bốn năm … ",
  "dn19:52.4": "hãy chờ ba năm … ",
  "dn19:52.5": "hãy chờ hai năm … ",
  "dn19:52.6": "hãy chờ một năm, sau một năm, chúng tôi cũng sẽ xuất gia từ bỏ gia đình sống đời không nhà; cảnh giới nào của ngài, cảnh giới ấy cũng sẽ là của chúng tôi.’ ",
  "dn19:53.1": "‘Thưa quý vị, một năm quá lâu, tôi không thể chờ quý vị một năm. ",
  "dn19:53.2": "Thưa quý vị, ai biết được mạng sống. ",
  "dn19:53.3": "Cần phải đi đến đời sau, cần phải suy xét bằng trí tuệ, cần phải làm việc thiện, cần phải sống đời phạm hạnh, không có người sinh ra mà không chết. ",
  "dn19:53.4": "Theo lời tôi nghe Phạm thiên nói về ‘mùi thịt’, chúng không dễ bị diệt đối với người sống tại gia, ",
  "dn19:53.5": "thưa quý vị, tôi sẽ xuất gia từ bỏ gia đình sống đời không nhà.’ ",
  "dn19:53.6": "‘Vậy thì Tôn giả Govinda hãy chờ bảy tháng, sau bảy tháng, chúng tôi cũng sẽ xuất gia từ bỏ gia đình sống đời không nhà; cảnh giới nào của ngài, cảnh giới ấy cũng sẽ là của chúng tôi.’ ",
  "dn19:54.1": "‘Thưa quý vị, bảy tháng quá lâu, tôi không thể chờ quý vị bảy tháng. ",
  "dn19:54.2": "Thưa quý vị, ai biết được mạng sống. ",
  "dn19:54.3": "Cần phải đi đến đời sau, cần phải suy xét bằng trí tuệ, cần phải làm việc thiện, cần phải sống đời phạm hạnh, không có người sinh ra mà không chết. ",
  "dn19:54.4": "Theo lời tôi nghe Phạm thiên nói về ‘mùi thịt’, chúng không dễ bị diệt đối với người sống tại gia, ",
  "dn19:54.5": "thưa quý vị, tôi sẽ xuất gia từ bỏ gia đình sống đời không nhà.’ ",
  "dn19:54.6": "‘Vậy thì Tôn giả Govinda hãy chờ sáu tháng …(v.v.)… ",
  "dn19:54.7": "hãy chờ năm tháng … ",
  "dn19:54.8": "hãy chờ bốn tháng … ",
  "dn19:54.9": "hãy chờ ba tháng … ",
  "dn19:54.10": "hãy chờ hai tháng … ",
  "dn19:54.11": "hãy chờ một tháng … ",
  "dn19:54.12": "hãy chờ nửa tháng, sau nửa tháng, chúng tôi cũng sẽ xuất gia từ bỏ gia đình sống đời không nhà; cảnh giới nào của ngài, cảnh giới ấy cũng sẽ là của chúng tôi.’ ",
  "dn19:55.1": "‘Thưa quý vị, nửa tháng quá lâu, tôi không thể chờ quý vị nửa tháng. ",
  "dn19:55.2": "Thưa quý vị, ai biết được mạng sống. ",
  "dn19:55.3": "Cần phải đi đến đời sau, cần phải suy xét bằng trí tuệ, cần phải làm việc thiện, cần phải sống đời phạm hạnh, không có người sinh ra mà không chết. ",
  "dn19:55.4": "Theo lời tôi nghe Phạm thiên nói về ‘mùi thịt’, chúng không dễ bị diệt đối với người sống tại gia, ",
  "dn19:55.5": "thưa quý vị, tôi sẽ xuất gia từ bỏ gia đình sống đời không nhà.’ ",
  "dn19:55.6": "‘Vậy thì Tôn giả Govinda hãy chờ bảy ngày, để chúng tôi căn dặn con em chúng tôi về việc trị vì, sau bảy ngày, chúng tôi cũng sẽ xuất gia từ bỏ gia đình sống đời không nhà; cảnh giới nào của ngài, cảnh giới ấy cũng sẽ là của chúng tôi.’ ",
  "dn19:55.7": "‘Thưa quý vị, bảy ngày thì không lâu, tôi sẽ chờ quý vị bảy ngày.’ ",
  "dn19:56.0": "6.6. Bẩm báo các đại Bà-la-môn v.v. ",
  "dn19:56.1": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda đi đến chỗ bảy đại Bà-la-môn và bảy trăm thanh niên đã tắm gội; sau khi đến, nói với bảy đại Bà-la-môn và bảy trăm thanh niên đã tắm gội: ",
  "dn19:56.2": "‘Nay xin quý vị hãy tìm một vị thầy khác để dạy chú thuật cho quý vị. ",
  "dn19:56.3": "Thưa quý vị, tôi muốn xuất gia từ bỏ gia đình sống đời không nhà. ",
  "dn19:56.4": "Theo lời tôi nghe Phạm thiên nói về ‘mùi thịt’, chúng không dễ bị diệt đối với người sống tại gia, ",
  "dn19:56.5": "thưa quý vị, tôi sẽ xuất gia từ bỏ gia đình sống đời không nhà.’ ",
  "dn19:56.6": "‘Xin Tôn giả Govinda đừng xuất gia từ bỏ gia đình sống đời không nhà. ",
  "dn19:56.7": "Thưa ngài, xuất gia ít uy lực và ít lợi lộc; ",
  "dn19:56.8": "còn nghề Bà-la-môn thì có đại uy lực và đại lợi lộc.’ ",
  "dn19:56.9": "‘Quý vị đừng nói như vậy: ‘Xuất gia ít uy lực và ít lợi lộc, còn nghề Bà-la-môn thì có đại uy lực và đại lợi lộc.’ ",
  "dn19:56.10": "Thưa quý vị, ngoài tôi ra, ai có uy lực lớn hơn hay lợi lộc lớn hơn? ",
  "dn19:56.11": "Vì tôi, thưa quý vị, nay đã như vua của các vua, như Phạm thiên của các Bà-la-môn, như thần của các gia chủ. ",
  "dn19:56.12": "Tôi sẽ từ bỏ tất cả những điều ấy mà xuất gia từ bỏ gia đình sống đời không nhà. ",
  "dn19:56.13": "Theo lời tôi nghe Phạm thiên nói về ‘mùi thịt’, chúng không dễ bị diệt đối với người sống tại gia. ",
  "dn19:56.14": "Thưa quý vị, tôi sẽ xuất gia từ bỏ gia đình sống đời không nhà.’ ",
  "dn19:56.15": "‘Nếu Tôn giả Govinda xuất gia từ bỏ gia đình sống đời không nhà, thì chúng tôi cũng xuất gia từ bỏ gia đình sống đời không nhà, cảnh giới nào của ngài, cảnh giới ấy cũng sẽ là của chúng tôi.’ ",
  "dn19:57.0": "6.7. Bẩm báo các bà vợ ",
  "dn19:57.1": "Rồi, thưa quý vị, Bà-la-môn Đại Govinda đi đến chỗ bốn mươi người vợ cùng dòng dõi; sau khi đến, nói với bốn mươi người vợ cùng dòng dõi: ",
  "dn19:57.2": "‘Các bà nào muốn, hãy trở về gia đình bên ngoại, hoặc tìm người chồng khác. ",
  "dn19:57.3": "Các bà, tôi muốn xuất gia từ bỏ gia đình sống đời không nhà. ",
  "dn19:57.4": "Theo lời tôi nghe Phạm thiên nói về ‘mùi thịt’, chúng không dễ bị diệt đối với người sống tại gia. ",
  "dn19:57.5": "Các bà, tôi sẽ xuất gia từ bỏ gia đình sống đời không nhà.’ ",
  "dn19:57.6": "‘Chính ngài là người thân đối với chúng tôi, những người cần người thân, ngài là chồng đối với chúng tôi, những người cần chồng. ",
  "dn19:57.7": "Nếu Tôn giả Govinda xuất gia từ bỏ gia đình sống đời không nhà, thì chúng tôi cũng xuất gia từ bỏ gia đình sống đời không nhà, cảnh giới nào của ngài, cảnh giới ấy cũng sẽ là của chúng tôi.’ ",
  "dn19:58.0": "6.8. Đại Govinda xuất gia ",
  "dn19:58.1": "Rồi, thưa quý vị, sau bảy ngày ấy, Bà-la-môn Đại Govinda cạo bỏ râu tóc, mặc y áo cà-sa, xuất gia từ bỏ gia đình sống đời không nhà. ",
  "dn19:58.2": "Sau khi Bà-la-môn Đại Govinda đã xuất gia, bảy vị vua Sát-đế-lỵ đã làm lễ quán đảnh, bảy đại Bà-la-môn và bảy trăm thanh niên đã tắm gội, bốn mươi người vợ cùng dòng dõi, nhiều ngàn Sát-đế-lỵ, nhiều ngàn Bà-la-môn, nhiều ngàn gia chủ, và các phụ nữ từ nhiều cung thất, cạo bỏ râu tóc, mặc y áo cà-sa, cùng xuất gia từ bỏ gia đình sống đời không nhà theo Bà-la-môn Đại Govinda. ",
  "dn19:58.3": "Được hội chúng ấy vây quanh, thưa quý vị, Bà-la-môn Đại Govinda du hành qua các làng mạc, thị trấn, các kinh đô. ",
  "dn19:58.4": "Thưa quý vị, vào thời đó, mỗi khi Bà-la-môn Đại Govinda đến bất kỳ làng hay thị trấn nào, ngài đều như vua của các vua, như Phạm thiên của các Bà-la-môn, như thần của các gia chủ. ",
  "dn19:58.5": "Lúc bấy giờ, khi người ta hắt hơi hay vấp ngã. ",
  "dn19:58.6": "Họ nói rằng: ",
  "dn19:58.7": "‘Kính lễ Bà-la-môn Đại Govinda, kính lễ vị tế sư của bảy nước.’ ",
  "dn19:59.1": "Thưa quý vị, Bà-la-môn Đại Govinda an trú, biến mãn một phương với tâm câu hữu với từ, cũng vậy với phương thứ hai, phương thứ ba, phương thứ tư. Như vậy, cùng khắp trên, dưới, ngang, và ở mọi nơi, đối với tất cả, cũng như đối với chính mình, ngài an trú, biến mãn khắp thế giới với tâm câu hữu với từ, rộng lớn, quảng đại, vô lượng, không thù hận, không sân hận. ",
  "dn19:59.2": "Với tâm câu hữu với bi …(v.v.)… ",
  "dn19:59.3": "với tâm câu hữu với hỷ …(v.v.)… ",
  "dn19:59.4": "với tâm câu hữu với xả …(v.v.)… không sân hận, ngài an trú biến mãn. ",
  "dn19:59.5": "Và ngài đã thuyết giảng con đường đưa đến cộng trú với Phạm thiên cho các đệ tử. ",
  "dn19:60.1": "Thưa quý vị, vào thời đó, các đệ tử của Bà-la-môn Đại Govinda nào đã hiểu trọn vẹn lời dạy. ",
  "dn19:60.2": "Khi thân hoại mạng chung, họ được sinh vào thiện thú, cõi Phạm thiên. ",
  "dn19:60.3": "Những ai không hiểu trọn vẹn lời dạy, khi thân hoại mạng chung, một số sinh vào cộng trú với chư thiên cõi Tha Hóa Tự Tại; ",
  "dn19:60.4": "một số sinh vào cộng trú với chư thiên cõi Hóa Lạc; ",
  "dn19:60.5": "một số sinh vào cộng trú với chư thiên cõi Đâu-suất; ",
  "dn19:60.6": "một số sinh vào cộng trú với chư thiên cõi Dạ-ma; ",
  "dn19:60.7": "một số sinh vào cộng trú với chư thiên cõi Ba Mươi Ba; ",
  "dn19:60.8": "một số sinh vào cộng trú với chư thiên cõi Tứ Đại Thiên Vương; ",
  "dn19:60.9": "những ai thấp nhất cũng sinh vào cộng trú với các càn-thát-bà. ",
  "dn19:60.10": "Như vậy, thưa quý vị, sự xuất gia của tất cả các thiện nam tử ấy không phải vô ích, không phải vô sinh, có kết quả, có lợi ích.’ ",
  "dn19:60.11": "Thế Tôn có nhớ điều ấy không?” ",
  "dn19:61.1": "“Ta nhớ, này Pañcasikha. ",
  "dn19:61.2": "Ta lúc ấy là Bà-la-môn Đại Govinda. ",
  "dn19:61.3": "Ta đã thuyết giảng con đường đưa đến cộng trú với Phạm thiên cho các đệ tử ấy. ",
  "dn19:61.4": "Nhưng đời sống phạm hạnh ấy của Ta, này Pañcasikha, không đưa đến nhàm chán, không đưa đến ly tham, không đưa đến đoạn diệt, không đưa đến an tịnh, không đưa đến thắng trí, không đưa đến giác ngộ, không đưa đến Niết-bàn, mà chỉ đưa đến tái sinh cõi Phạm thiên. ",
  "dn19:61.5": "Còn đời sống phạm hạnh này của Ta, này Pañcasikha, hoàn toàn đưa đến nhàm chán, đưa đến ly tham, đưa đến đoạn diệt, đưa đến an tịnh, đưa đến thắng trí, đưa đến giác ngộ, đưa đến Niết-bàn. ",
  "dn19:61.6": "Và này Pañcasikha, đời sống phạm hạnh này đưa đến nhàm chán, đưa đến ly tham, đưa đến đoạn diệt, đưa đến an tịnh, đưa đến thắng trí, đưa đến giác ngộ, đưa đến Niết-bàn là gì? ",
  "dn19:61.7": "Đó chính là Bát Thánh Đạo. ",
  "dn19:61.8": "Đó là—chánh kiến, chánh tư duy, chánh ngữ, chánh nghiệp, chánh mạng, chánh tinh tấn, chánh niệm, chánh định. ",
  "dn19:61.9": "Này Pañcasikha, đây là đời sống phạm hạnh hoàn toàn đưa đến nhàm chán, đưa đến ly tham, đưa đến đoạn diệt, đưa đến an tịnh, đưa đến thắng trí, đưa đến giác ngộ, đưa đến Niết-bàn. ",
  "dn19:62.1": "Này Pañcasikha, các đệ tử của Ta nào hiểu trọn vẹn lời dạy, do đoạn tận các lậu hoặc, với thắng trí tự mình chứng ngộ, chứng đạt và an trú ngay trong đời này sự giải thoát của tâm không còn lậu hoặc và sự giải thoát bằng trí tuệ; ",
  "dn19:62.2": "những ai không hiểu trọn vẹn lời dạy, do đoạn tận năm hạ phần kiết sử, là bậc hóa sinh, nhập Niết-bàn tại đó, không còn trở lại thế giới này. ",
  "dn19:62.3": "Những ai không hiểu trọn vẹn lời dạy, một số do đoạn tận ba kiết sử và làm nhẹ bớt tham, sân, si, là bậc Nhất Lai, chỉ còn trở lại đời này một lần nữa rồi chấm dứt khổ đau. ",
  "dn19:62.4": "Những ai không hiểu trọn vẹn lời dạy, một số do đoạn tận ba kiết sử, là bậc Dự Lưu, không còn bị đọa vào ác thú, chắc chắn sẽ đạt đến Giác Ngộ. ",
  "dn19:62.5": "Như vậy, này Pañcasikha, sự xuất gia của tất cả các thiện nam tử ấy không phải vô ích, không phải vô sinh, có kết quả, có lợi ích.” ",
  "dn19:62.6": "Thế Tôn đã nói như vậy. ",
  "dn19:62.7": "Pañcasikha con của càn-thát-bà hoan hỷ, tín thọ lời Thế Tôn dạy, tán thán, đảnh lễ Thế Tôn, đi nhiễu bên phải rồi biến mất ngay tại đó. ",
  "dn19:62.8": "Kinh Đại Điển Tôn thứ sáu đã kết thúc. "
}

